    let mut queue: VecDeque<(usize, usize)> = VecDeque::new();

    for source in sources {
        let r = source[0] as usize;
        let c = source[1] as usize;
        let color = source[2];

        // Initial state
        dist[r][c] = (0, color);
        grid[r][c] = color;
        queue.push_back((r, c));
    }

    let directions = [(0, 1), (0, -1), (1, 0), (-1, 0)];

    while let Some((r, c)) = queue.pop_front() {
        let current_time = dist[r][c].0;
        let current_color = dist[r][c].1;

        for &(dr_i64, dc_i64) in directions.iter() {
            let nr_i64 = r as i64 + dr_i64;
            let nc_i64 = c as i64 + dc_i64;

            if nr_i64 >= 0 && nr_i64 < n && nc_i64 >= 0 && nc_i64 < m {
                let nr = nr_i64 as usize;
                let nc = nc_i64 as usize;
                let next_time = current_time + 1;

                let (existing_time, existing_color) = dist[nr][nc];

                // Check if the new arrival is better than the existing one
                // 1. If it arrives strictly earlier (next_time < existing_time)
                // 2. If it arrives at the same time, but has a strictly larger color (next_time == existing_time AND current_color > existing_color)
                // Note: The problem states: "If multiple colors arrive at the same time step, the cell adopts the maximum color."
                // Since we are processing level by level (BFS), we naturally find the minimum time first.
                // If we reach a cell (nr, nc) at time T, and it already has a color from time T, we must check colors.

                let should_update = if next_time < existing_time {
                    true
                } else if next_time == existing_time {
                    // Tie in time, check color
                    current_color > existing_color
                } else {
                    false
                };

                if should_update {
                    // Update distance and color
                    dist[nr][nc] = (next_time, current_color);
                    grid[nr][nc] = current_color;

                    // Add to queue for further spreading
                    queue.push_back((nr, nc));
                }
            }
        }
    }

    grid
